import React from "react";

function Login() {
  return (
    <div style={styles.container}>

      {/* Header */}
      <header style={styles.header}>
        <h2></h2>
      </header>

      {/* Login Card */}
      <div style={styles.main}>
        <div style={styles.card}>
          <h2>Login</h2>

          <input
            type="text"
            placeholder="Email"
            style={styles.input}
          />

          <input
            type="password"
            placeholder="Password"
            style={styles.input}
          />

          <button style={styles.button}>Login</button>

          <p style={styles.text}>
            Don't have an account? <span style={styles.link}>Register</span>
          </p>
        </div>
      </div>

      {/* Footer */}
      <footer style={styles.footer}>
        <p>© 2026 MediCare. All rights reserved.</p>
      </footer>

    </div>
  );
}

export default Login;

const styles = {
  container: {
    fontFamily: "Arial, sans-serif",
    height: "100vh",
    display: "flex",
    flexDirection: "column",
  },

  header: {
    backgroundColor: "#2c3e50",
    color: "white",
    padding: "15px",
    textAlign: "center",
  },

  main: {
    flex: 1,
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    backgroundColor: "#f4f6f9",
  },

  card: {
    backgroundColor: "white",
    padding: "30px",
    borderRadius: "10px",
    width: "320px",
    textAlign: "center",
    boxShadow: "0 4px 10px rgba(0,0,0,0.1)",
  },

  input: {
    width: "100%",
    padding: "10px",
    margin: "10px 0",
    borderRadius: "5px",
    border: "1px solid #ccc",
  },

  button: {
    width: "100%",
    padding: "10px",
    backgroundColor: "#2c3e50",
    color: "white",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer",
    marginTop: "10px",
  },

  text: {
    marginTop: "15px",
    fontSize: "14px",
  },

  link: {
    color: "#2c3e50",
    fontWeight: "bold",
    cursor: "pointer",
  },

  footer: {
    backgroundColor: "#2c3e50",
    color: "white",
    textAlign: "center",
    padding: "10px",
  },
};
